      "Bash(npx @claude-flow*)",
      "Bash(npx claude-flow*)",
      "Bash(node .claude/*)",
      "mcp__claude-flow__:*"
    ],
    "deny": [
      "Read(./.env)",
      "Read(./.env.*)"
    ]
  },
  "attribution": {
    "commit": "Co-Authored-By: claude-flow <ruv@ruv.net>",
    "pr": "🤖 Generated with [claude-flow](https://github.com/ruvnet/claude-flow)"
  },
  "env": {
    "CLAUDE_CODE_EXPERIMENTAL_AGENT_TEAMS": "1",
    "CLAUDE_FLOW_V3_ENABLED": "true",
    "CLAUDE_FLOW_HOOKS_ENABLED": "true"
  },
  "claudeFlow": {
    "version": "3.0.0",
    "enabled": true,
    "platform": {
      "os": "windows",
      "arch": "x64",
      "shell": "powershell"
    },
    "modelPreferences": {
      "default": "claude-opus-4-6",
      "routing": "claude-haiku-4-5-20251001"
    },
    "agentTeams": {
      "enabled": true,
      "teammateMode": "auto",
      "taskListEnabled": true,
      "mailboxEnabled": true,
      "coordination": {
        "autoAssignOnIdle": true,
        "trainPatternsOnComplete": true,
        "notifyLeadOnComplete": true,
        "sharedMemoryNamespace": "agent-teams"
      },
      "hooks": {
        "teammateIdle": {
          "enabled": true,
          "autoAssign": true,
          "checkTaskList": true
        },
        "taskCompleted": {
          "enabled": true,
          "trainPatterns": true,
          "notifyLead": true
        }
      }
    },
    "swarm": {
      "topology": "hierarchical-mesh",
      "maxAgents": 15
    },
    "memory": {
      "backend": "hybrid",
      "enableHNSW": true,
      "learningBridge": {
        "enabled": true
      },
      "memoryGraph": {
        "enabled": true
      },
      "agentScopes": {
        "enabled": true
      }
    },
    "neural": {
      "enabled": true
    },
    "daemon": {
      "autoStart": false,
      "workers": [
        "map",
        "audit",
        "optimize"
      ],
      "schedules": {
        "audit": {
          "interval": "4h",
          "priority": "critical"
        },
        "optimize": {
          "interval": "2h",
          "priority": "high"
        }
      }
    },
    "learning": {
      "enabled": true,
      "autoTrain": true,
      "patterns": [
        "coordination",
        "optimization",
        "prediction"
      ],
      "retention": {
        "shortTerm": "24h",
        "longTerm": "30d"
      }
    },
    "adr": {
      "autoGenerate": true,
      "directory": "/docs/adr",
      "template": "madr"
    },
    "ddd": {
      "trackDomains": true,
      "validateBoundedContexts": true,
      "directory": "/docs/ddd"
    },
    "security": {
      "autoScan": true,
      "scanOnEdit": true,
      "cveCheck": true,
      "threatModel": true
    }
  }
}

