import { useState } from "react";
import { useLocation } from "wouter";
import Layout from "@/components/layout";
import ScoreGauge from "@/components/score-gauge";
import {
  QUIZ_QUESTIONS,
  calculateScore,
  getScoreCategory,
} from "@/data/quiz-questions";
import { OFFERS } from "@/data/offers";
import {
  Shield,
  ArrowRight,
  Check,
  Lock,
  Star,
  Phone,
  Users,
  FileText,
  Mail,
  Search,
  ChevronRight,
} from "lucide-react";
import { cn } from "@/lib/utils";

// ── Payment plan data ─────────────────────────────────────────────────────────
const BASE_OFFER = OFFERS["blindaje-personal"];
const PLUS_OFFER = OFFERS["blindaje-personal-plus"];

type Stage = "intro" | "questions" | "email-gate" | "result" | "upsell";

// ── Intro screen ──────────────────────────────────────────────────────────────
function IntroScreen({ onStart }: { onStart: () => void }) {
  return (
    <div className="flex flex-col items-center text-center space-y-6">
      {/* Icon */}
      <div className="relative">
        <div className="w-20 h-20 rounded-full bg-[#FFD400]/10 border border-[#FFD400]/30 flex items-center justify-center">
          <Shield className="w-10 h-10 text-[#FFD400]" />
        </div>
        <span className="absolute -top-1 -right-1 bg-[#FFD400] text-[#0F2438] text-[10px] font-black px-2 py-0.5 rounded-full uppercase tracking-wide">
          GRATIS
        </span>
      </div>

      <div className="space-y-2">
        <h1 className="text-2xl font-black text-white leading-tight">
          Descubre tu<br />
          <span className="text-[#FFD400]">Privacy Score</span>
        </h1>
        <p className="text-slate-400 text-sm leading-relaxed">
          15 preguntas. 3 minutos. Descubre qué tan seguro eres online
          y qué pasos concretos debes tomar para protegerte.
        </p>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-3 gap-3 w-full">
        {[
          { value: "15", label: "preguntas" },
          { value: "3 min", label: "duración" },
          { value: "100%", label: "gratuito" },
        ].map(({ value, label }) => (
          <div
            key={label}
            className="glass-card rounded-xl p-3 flex flex-col items-center gap-0.5"
          >
            <span className="text-xl font-black text-[#FFD400]">{value}</span>
            <span className="text-[10px] text-slate-400 uppercase tracking-wide">{label}</span>
          </div>
        ))}
      </div>

      {/* Topics preview */}
      <div className="w-full space-y-2">
        <p className="text-xs text-slate-500 uppercase tracking-wider font-semibold">Temáticas del test</p>
        <div className="flex flex-wrap gap-2 justify-center">
          {["Contraseñas", "2FA", "VPN", "Phishing", "Actualizaciones", "Cifrado", "Privacidad RRSS", "Brechas de datos"].map((t) => (
            <span
              key={t}
              className="px-2.5 py-1 bg-slate-800/60 border border-slate-700 rounded-full text-xs text-slate-300"
            >
              {t}
            </span>
          ))}
        </div>
      </div>

      <button
        onClick={onStart}
        className="cta-shimmer w-full bg-[#FFD400] hover:bg-[#FFE033] text-[#0F2438] font-black py-4 px-6 rounded-xl shadow-lg hover:shadow-[#FFD400]/30 transition-all duration-300 flex items-center justify-center gap-2 text-base"
      >
        Empezar el test
        <ArrowRight className="w-5 h-5" />
      </button>

      <p className="text-xs text-slate-600">
        Sin registro. Sin spam. Solo tu puntuación.
      </p>
    </div>

