import { useEffect, useState } from "react";
import { type ScoreCategory } from "@/data/quiz-questions";

interface ScoreGaugeProps {
  score: number;
  category: ScoreCategory;
  size?: number;
}

export default function ScoreGauge({ score, category, size = 160 }: ScoreGaugeProps) {
  const [animatedScore, setAnimatedScore] = useState(0);
  const [animatedOffset, setAnimatedOffset] = useState(283);

  const radius = 45;
  const circumference = 2 * Math.PI * radius; // ~283

  useEffect(() => {
    const duration = 1500;
    const startTime = performance.now();

    function animate(now: number) {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      // ease-out cubic
      const eased = 1 - Math.pow(1 - progress, 3);

      setAnimatedScore(Math.round(eased * score));
      setAnimatedOffset(circumference - eased * (circumference * score) / 100);

      if (progress < 1) requestAnimationFrame(animate);
    }

    requestAnimationFrame(animate);
  }, [score, circumference]);

  const strokeColorMap: Record<string, string> = {
    green: "#4ade80",
    blue: "#60a5fa",
    yellow: "#facc15",
    orange: "#fb923c",
    red: "#f87171",
  };
  const strokeColor = strokeColorMap[category.color] ?? "#FFD400";

  return (
    <div className="flex flex-col items-center gap-3">
      <div className="relative" style={{ width: size, height: size }}>
        <svg
          width={size}
          height={size}
          viewBox="0 0 100 100"
          className="rotate-[-90deg]"
        >
          {/* Background track */}
          <circle
            cx="50"
            cy="50"
            r={radius}
            fill="none"
            stroke="rgba(255,255,255,0.08)"
            strokeWidth="8"
          />
          {/* Animated progress arc */}
          <circle
            cx="50"
            cy="50"
            r={radius}
            fill="none"
            stroke={strokeColor}
            strokeWidth="8"
            strokeLinecap="round"
            strokeDasharray={circumference}
            strokeDashoffset={animatedOffset}
            style={{ transition: "stroke 0.3s ease" }}
          />
        </svg>
        {/* Score number overlay */}
        <div className="absolute inset-0 flex flex-col items-center justify-center">
          <span className={`text-4xl font-black ${category.textColor}`}>
            {animatedScore}
          </span>
          <span className="text-xs text-slate-400 font-medium">/100</span>
        </div>
      </div>

      {/* Category badge */}
      <div className={`flex items-center gap-2 px-4 py-2 rounded-full border ${category.bgColor} ${category.borderColor}`}>
        <span className="text-lg">{category.emoji}</span>
        <span className={`font-bold text-sm ${category.textColor}`}>{category.label}</span>
      </div>

      {/* Percentile */}
      <p className="text-xs text-slate-400 text-center">
        Estás {category.percentile}
      </p>
    </div>
  );
}

